import { Hono } from 'hono'
import { zValidator } from '@hono/zod-validator'
import { z } from 'zod'

const schema = z.object({
  email: z.string().email().trim().toLowerCase(),
  age: z.coerce.number().int().min(13),
})

const app = new Hono()

app.post(
  '/register',
  zValidator('json', schema, (result, c) => {
    if (!result.success)
      return c.json({ error: 'Invalid input', issues: result.error.flatten() }, 400)
  }),
  (c) => {
    const { email, age } = c.req.valid('json') // fully typed & sanitized
    return c.json({ email, age })
  }
)

import { Hono } from 'hono'
import { jwt } from 'hono/jwt'

const app = new Hono()
const SECRET = process.env.JWT_SECRET!

// Role-check middleware (runs after jwt())
const requireAdmin = async (c: any, next: any) => {
  const payload = c.get('jwtPayload')
  if (payload?.role !== 'admin') return c.json({ error: 'Forbidden' }, 403)
  await next()
}

app.use('/admin/*', jwt({ secret: SECRET }))
app.use('/admin/*', requireAdmin)

app.get('/admin/dashboard', (c) => {
  const { sub, role } = c.get('jwtPayload')
  return c.json({ user: sub, role })
})

export default app

import { Hono } from 'hono'
import { HTTPException } from 'hono/http-exception'

const app = new Hono()

app.get('/secret', (c) => {
  throw new HTTPException(403, { message: 'Forbidden' })
})

app.onError((err, c) => {
  if (err instanceof HTTPException) {
    return c.json({ success: false, error: { code: err.status, message: err.message } }, err.status)
  }
  console.error(err)
  return c.json({ success: false, error: { code: 500, message: 'Internal Server Error' } }, 500)
})

app.notFound((c) => c.json({ success: false, error: { code: 404, message: 'Not Found' } }, 404))

export default app

import { drizzle } from 'drizzle-orm/neon-http'
import { neon } from '@neondatabase/serverless'
import * as schema from './schema'

const sql = neon(process.env.DATABASE_URL!)
const db = drizzle(sql, { schema })

// BAD — N+1: one query per post to fetch its comments
app.get('/posts/bad', async (c) => {
  const posts = await db.select().from(schema.posts)
  const result = await Promise.all(
    posts.map(p =>
      db.select().from(schema.comments).where(eq(schema.comments.postId, p.id))
    )
  )
  return c.json(result)
})

// GOOD — single JOIN via Drizzle relational API
app.get('/posts', async (c) => {
  const posts = await db.query.posts.findMany({
    with: { comments: true },
  })
  return c.json(posts)
})

import { Hono } from 'hono'
import { compress } from 'hono/compress'
import { Pool } from 'pg'

const pool = new Pool({ connectionString: process.env.DATABASE_URL })

const app = new Hono()

app.use('*', async (c, next) => {
  c.set('db', pool)
  await next()
})

app.use('/api/*', compress())

app.get('/api/posts', async (c) => {
  const db = c.get('db')
  const [posts, tags] = await Promise.all([
    db.query('SELECT * FROM posts LIMIT 20'),
    db.query('SELECT * FROM tags')
  ])
  c.header('Cache-Control', 'public, max-age=60')
  return c.json({ posts: posts.rows, tags: tags.rows })
})

export default app

